    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 breaking change: default renderer changed from Professional to System.
        // Explicitly set the renderer to preserve the .NET 8 appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;
        _statusStrip.Items.Add(new ToolStripStatusLabel("Ready"));
        Controls.Add(_statusStrip);
    }
}

public class MyDropDownEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(
        System.ComponentModel.ITypeDescriptorContext context) =>
        UITypeEditorEditStyle.DropDown;

    public override object EditValue(
        System.ComponentModel.ITypeDescriptorContext context,
        IServiceProvider provider,
        object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService == null)
            return value;

        var control = CreateEditControl(value);
        // .NET 9 breaking change: DropDownControl now throws ArgumentNullException for null.
        if (control == null)
            return value;

        editorService.DropDownControl(control);
        return control.Tag ?? value;
    }

    private static Control CreateEditControl(object value)
    {
        var listBox = new ListBox();
        listBox.Tag = value;
        return listBox;
    }
}

